mapper.sql:
WHERE 1 = 1

    AND t.user_id = #{userId}


    AND t.task_type = #{taskType}


    AND t.status = #{status}


    AND (
        t.user_nickname LIKE CONCAT('%', #{keyword}, '%')
        OR t.account LIKE CONCAT('%', #{keyword}, '%')
        OR t.scope_json LIKE CONCAT('%', #{keyword}, '%')
        OR t.file_name LIKE CONCAT('%', #{keyword}, '%')
        OR t.fail_reason LIKE CONCAT('%', #{keyword}, '%')
        OR t.reason LIKE CONCAT('%', #{keyword}, '%')
    )

mapper.select:
SELECT t.id, t.task_type, t.user_id, t.user_nickname, t.account, t.status, t.scope_json, t.format, t.file_name, t.fail_reason, t.verify_type, t.reason, t.expire_at, t.cooling_off_expire_at, t.completed_at, t.cancelled_at, t.created_at, t.updated_at FROM (
) t
ORDER BY t.created_at DESC, t.id DESC LIMIT #{pageSize} OFFSET #{offset}
